import React from 'react';
import moment from 'moment';
import DataTable from '../../components/common/DataTable';
import { createResourceService } from '../../services/api.service';
import { icons } from '../../config/icons';
import useForm from '../../hooks/useForm';
import { FormInput } from '../../components/common/FormFields';

const TableForm = ({ item, onSave }) => {
    const isEditMode = Boolean(item);
    
    const schema = {
        fn: { required: true, label: 'First Name' },
        sn: { required: true, label: 'Last Name' }
    };

    const { values, errors, handleChange, handleSubmit } = useForm({
        fn: isEditMode ? item.fn ?? '' : '',
        sn: isEditMode ? item.sn ?? '' : '',
    }, schema);

    const handleSave = (formValues) => {
        const formData = new FormData();
        Object.keys(formValues).forEach(key => formData.append(key, formValues[key]));
        onSave(formData, item?.id);
    };

    return (
        <form className='form-case' noValidate id='Table_form' onSubmit={handleSubmit(handleSave)} >
            <FormInput label="First Name" name="fn" placeholder="First Name" value={values.fn} error={errors.fn} onChange={handleChange} required />
            <FormInput label="Last Name" name="sn" placeholder="Last Name" value={values.sn} error={errors.sn} onChange={handleChange} required />
        </form>
    );
};

const tableService = createResourceService('employees');

const TableCheckbox = () => {
    const tableColumns = [
        { key: 'id', label: 'ID', type: 1, sortable: true },
        { key: 'fn', label: 'First Name', type: 1, sortable: true },
        { key: 'sn', label: 'Last Name', type: 1, sortable: true },
        { key: 'email', label: 'Email', type: 1, sortable: true },
    ];

    const bulkActions = [
        { 
            text: 'Bulk Delete', 
            icon: icons.delete, 
            className: 'btn-danger', 
            onClick: (ids, clearSelection, refetch) => {
                if (window.confirm(`Delete ${ids.length} items?`)) {
                    // This is a sample placeholder for bulk delete logic
                    console.log('Bulk delete:', ids);
                    clearSelection();
                    refetch();
                }
            } 
        }
    ];

    return (
        <DataTable
            resourceName='Table'
            apiService={tableService}
            columns={tableColumns}
            FormComponent={TableForm}
            config={{ 
                title: <span><h2>Checkbox Table</h2><p>Bulk actions demo</p></span>,
                showCheckbox: true,
                bulkActions: bulkActions,
                searchables: ['fn', 'sn', 'email'],
                modalWidth: 'w-md'
            }}
        />
    );
};

export default TableCheckbox;
